(function($, window, document, undefined) {

	let playAutoStatus = false;
	let percentageHit = {
		'playback0' : 0,
		'playback25' : 25,
		'playback50' : 50,
		'playback75' : 75,
		'playback100' : 100
	}

	function eventHandler(playerEvent)
	{

		let current =  null;
		playerEvent.powa.on(PoWa.EVENTS.ALL, function(event, eventName){	
			switch(eventName)
			{
				case PoWa.EVENTS.AD_FIRST_FRAME:
					analytics(playerEvent.videoData, 'ADFIRSTFRAME', event);
					break;
				case PoWa.EVENTS.AD_LOADED:
					analytics(playerEvent.videoData, 'ADLOADED', event);
					break;
				case PoWa.EVENTS.AD_ERROR:
				case PoWa.EVENTS.AD_SETUP_ERROR:
					analytics(playerEvent.videoData, 'ADERROR', event);
					break;
				case PoWa.EVENTS.AD_COMPLETE:
					analytics(playerEvent.videoData, 'ADCOMPLETE', event);
					break;
				case PoWa.EVENTS.AD_SKIP:
				case PoWa.EVENTS.AD_BAR_SKIP:
					analytics(playerEvent.videoData, 'ADSKIP', event);
					break;
				case PoWa.EVENTS.START:
					analytics(playerEvent.videoData, 'START', event);
					break;
				case PoWa.EVENTS.POWA_ERROR:
				case PoWa.EVENTS.ERROR:
					analytics(playerEvent.videoData, 'ERROR', event);
					break;
				case PoWa.EVENTS.MEDIA_START:
					analytics(playerEvent.videoData, 'PLAY', event);
					break;
				case PoWa.EVENTS.PAUSE:
					analytics(playerEvent.videoData, 'PAUSE', event);
					break;
				case PoWa.EVENTS.MUTED:
					analytics(playerEvent.videoData, 'MUTED', event);
					break;
				case PoWa.EVENTS.COMPLETE:
					analytics(playerEvent.videoData, 'COMPLETE', event);
					break;
				case PoWa.EVENTS.PLAYBACK_0:
				case PoWa.EVENTS.PLAYBACK_25:
				case PoWa.EVENTS.PLAYBACK_50:
				case PoWa.EVENTS.PLAYBACK_75:
				case PoWa.EVENTS.PLAYBACK_100:
					analyticsCurrentTime(playerEvent.videoData, event, eventName);
                //case PoWa.EVENTS.TIME:

				break;
			}
		});
	}


	//Analytics
	function analyticsCurrentTime(videoData, event, eventName)
	{
		let percentage = percentageHit[eventName]
		let currentTime = event.powa.getStatus()
		window.dataLayer.push({
			'event': 'video',
			'video-id': videoData._id,
			'video-name': videoData.headlines.basic,
			'video-action': 'Play Progress ' + percentage,
			'gtm.videoPercent': percentage,
			'gtm.videoDuration': currentTime.duration,
			'gtm.videoCurrentTime': currentTime.time
		})
	}


	function analytics(videoData, eventType, event)
	{
        let currentTime = event.powa.getStatus()
		switch(eventType)
		{
			case 'START':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Start',
					'video-start': 1,
					'gtm.videoDuration': currentTime.duration,
					'gtm.videoCurrentTime': 0,
					'video-autoplay': (playAutoStatus)?'Yes':'No',
				});
			break;
			case 'ERROR':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Error - ' + currentTime.details
				});
			break;
			case 'PLAY':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Play',
					'video-play': 1
				});
			break;
			case 'PAUSE':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Pause',
					'gtm.videoDuration': currentTime.duration,
					'gtm.videoCurrentTime': currentTime.time
				});
			break;
			case 'MUTED':
				if(currentTime.muted == false){
					dataLayer.push({
						'event': 'video',
						'video-id': videoData._id,
						'video-name': videoData.headlines.basic,
						'video-action': 'Video Unmuted',
						'gtm.videoDuration': currentTime.duration,
						'gtm.videoCurrentTime': currentTime.time,
						'video-unmute': 1
					})
				}
			break;
			case 'COMPLETE':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Complete',
					'gtm.videoDuration': currentTime.duration,
					'gtm.videoCurrentTime': currentTime.time,
					'video-complete': 1
				})
			break;
			case 'ADFIRSTFRAME':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Ad Start',
					'ad-start': 1
				})
			break;
			case 'ADERROR':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Ad Error - ' + event.error,
					'ad-error': 1
				})
			break;
			case 'ADSKIP':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Ad Skipped',
					'ad-skip': 1
				})
			break;
			case 'ADCOMPLETE':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Ad Complete',
					'ad-complete': 1
				})
			break;
			case 'ADLOADED':
				dataLayer.push({
					'event': 'video',
					'video-id': videoData._id,
					'video-name': videoData.headlines.basic,
					'video-action': 'Ad Loaded',
					'ad-loaded': 1
				})
			break;
		}

	}

	function init () {
		$('.powa').each(function(){
			let play = $(this).attr('id');
			playAutoStatus = $('#'+play).data("autoplay");
			eventHandler(window.powas[play]);
		});
		
	}

	window.addEventListener('powaReady', function(customEvent){
			init();
	});

})(jQuery, window, document);
